export const validatePayment = (values) => {
  const errors = {};

  if (!values?.bankName?.trim() || values.bankName.trim().length < 4)
    errors.bankName = "Escribe un nombre de banco vÃ¡lido";

  if (!values?.cardNumber?.trim() || values.cardNumber.trim().length !== 16)
    errors.cardNumber = "Escribe un nÃºmero de tarjeta vÃ¡lido";

  if (!values?.placeHolder?.trim() || values.placeHolder.trim().length < 10)
    errors.placeHolder = "Escribe nombre de titular vÃ¡lido";

  if (!values?.expiryDate?.trim() || values.expiryDate.trim().length !== 5) {
    errors.expiryDate = "La fecha de expiraciÃ³n no es vÃ¡lida";
  } else {
    const date = values.expiryDate.split("/"); // [12,26]
    const currentYear = new Date().getFullYear().toString().slice(-2);
    if (Number(date[0]) > 12 || Number(date[0]) < 1)
      errors.expiryDate = "El mes en la fecha de expiraciÃ³n no es vÃ¡lido";
    else if (Number(date[1]) < Number(currentYear))
      errors.expiryDate = "El aÃ±o en la fecha de expiraciÃ³n no es vÃ¡lido";
  }

  if (!values?.cvv?.trim() || values.cvv.trim().length !== 3) {
    errors.cvv = "Escribe un cvv vÃ¡lido";
  } else if (isNaN(values.cvv)) {
    errors.cvv = "El cvv debe contener solo nÃºmeros vÃ¡lidos";
  }

  return errors;
};
